mapper.select:
SELECT scene.name sceneName, area.name areaName, ap.name apName, ns.time, IFNULL((ns.networkDelay),0) networkDelay FROM scene LEFT JOIN networkspeed ns ON ns.`sceneId`=scene.`id` LEFT JOIN area ON ns.`areaId`=area.`id` LEFT JOIN ap ON ns.`apId`=ap.`id` WHERE 1=1
and scene.id=#{sceneId}
order by scene.id

SELECT scene.name sceneName, area.name areaName, ap.name apName, ns.time, IFNULL((ns.networkDelay),0) networkDelay FROM area LEFT JOIN networkspeed ns ON ns.`areaId`=area.`id` LEFT JOIN scene ON ns.`sceneId`=scene.`id` LEFT JOIN ap ON ns.`apId`=ap.`id` WHERE 1=1
and area.sceneId=#{sceneId}
order by scene.id

SELECT scene.name sceneName, area.name areaName, ap.name apName, ns.time, IFNULL((ns.networkDelay),0) networkDelay FROM ap LEFT JOIN networkspeed ns ON ns.`apId`=ap.`id` LEFT JOIN scene ON ns.`sceneId`=scene.`id` LEFT JOIN area ON ns.`areaId`=area.`id` WHERE 1=1
and ap.areaId=#{areaId}
order by scene.id

SELECT ap.id,ap.name apName,scene.name sceneName, area.name areaName FROM networkspeed ns LEFT JOIN scene ON scene.id=ns.sceneId LEFT JOIN area ON ns.areaId=area.id LEFT JOIN ap ON ns.apId=ap.id WHERE 1=1
and scene.name IS NOT NULL
and scene.name IS NOT NULL and scene.id=#{sceneId}
and area.name IS NOT NULL and area.id=#{areaId}

SELECT ns.`id`, ns.`networkDelay`, ns.`downloadSpeed`, ns.`uploadSpeed`, ns.`time`, ns.`address`, ns.`macAddress`, ns.`macAddress5G`, ns.`sceneId`, ns.`areaId`, ns.`apId`, ns.`speedometer`, scene.`name` sceneName, area.`name` areaName, ap.`name` apName FROM networkspeed ns LEFT JOIN scene ON ns.sceneId=scene.id LEFT JOIN area ON ns.areaId =area.id LEFT JOIN ap ON ns.apId=ap.id WHERE 1=1 and ns.networkDelay >= ${networkDelayPassValue}
AND scene.name=#{sceneName}
AND area.name=#{areaName}
AND ap.name=#{apName}

SELECT ns.`id`, ns.`networkDelay`, ns.`downloadSpeed`, ns.`uploadSpeed`, ns.`time`, ns.`address`, ns.`macAddress`, ns.`macAddress5G`, ns.`sceneId`, ns.`areaId`, ns.`apId`, ns.`speedometer`, scene.`name` sceneName, area.`name` areaName, ap.`name` apName FROM networkspeed ns LEFT JOIN scene ON ns.sceneId=scene.id LEFT JOIN area ON ns.areaId =area.id LEFT JOIN ap ON ns.apId=ap.id WHERE 1=1 and ns.networkDelay < ${networkDelayPassValue}
AND scene.name=#{sceneName}
AND area.name=#{areaName}
AND ap.name=#{apName}

SELECT ns.`id`, ns.`networkDelay`, ns.`downloadSpeed`, ns.`uploadSpeed`, ns.`time`, ns.`address`, ns.`macAddress`, ns.`macAddress5G`, ns.`sceneId`, ns.`areaId`, ns.`apId`, ns.`speedometer`, scene.`name` sceneName, area.`name` areaName, ap.`name` apName FROM networkspeed ns LEFT JOIN scene ON ns.sceneId=scene.id LEFT JOIN area ON ns.areaId =area.id LEFT JOIN ap ON ns.apId=ap.id WHERE 1=1
AND scene.name=#{sceneName}
AND area.name=#{areaName}
AND ap.name=#{apName}
